import html, json

def escape_for_html_context(text: str) -> str:
    return html.escape(text, quote=True)

def escape_for_json_string(text: str) -> str:
    # json.dumps already escapes backslashes, quotes, and control characters
    return json.dumps(text)[1:-1]  # strip outer quotes

def escape_for_sql_literal(text: str, dialect: str = "postgres") -> str:
    # Never use this for untrusted input in real SQL — use parameterised queries.
    # This is illustrative only.
    if dialect == "postgres":
        return text.replace("'", "''")
    raise ValueError(f"Unsupported dialect: {dialect}")

from dataclasses import dataclass
from enum import Enum

class ContentSource(Enum):
    SYSTEM_INSTRUCTION = "system"
    USER_MESSAGE       = "user"
    RETRIEVED_DOC      = "retrieved_doc"
    TOOL_RESULT        = "tool_result"
    SUB_AGENT_OUTPUT   = "sub_agent_output"

TRUST_LEVEL = {
    ContentSource.SYSTEM_INSTRUCTION: "high",
    ContentSource.USER_MESSAGE:       "medium",
    ContentSource.RETRIEVED_DOC:      "low",
    ContentSource.TOOL_RESULT:        "low",
    ContentSource.SUB_AGENT_OUTPUT:   "medium",
}

@dataclass
class WrappedContent:
    source: ContentSource
    raw_text: str
    doc_id: str = ""

    def to_context_block(self) -> str:
        trust = TRUST_LEVEL[self.source]
        tag = self.source.value
        id_attr = f' id="{self.doc_id}"' if self.doc_id else ""
        return (
            f"<{tag} trust=\"{trust}\"{id_attr}>\n"
            f"{self.raw_text}\n"
            f"</{tag}>"
        )

def build_structured_prompt(
    instructions: str,
    user_message: str,
    retrieved_docs: list[WrappedContent],
) -> str:
    parts = [
        WrappedContent(ContentSource.SYSTEM_INSTRUCTION, instructions).to_context_block(),
    ]
    for doc in retrieved_docs:
        parts.append(doc.to_context_block())
    parts.append(
        WrappedContent(ContentSource.USER_MESSAGE, user_message).to_context_block()
    )
    return "\n\n".join(parts)

from dataclasses import dataclass, field
from typing import Any
import json, re

@dataclass
class OutputValidationResult:
    allowed: bool
    reason: str = ""
    sanitised_text: str = ""

BLOCKED_CONTENT_PATTERNS = [
    re.compile(r"(synthesis route|exact (proportions|dose|ratio))", re.I),
    re.compile(r"(exfil|send.{0,30}(to http|webhook|external))", re.I),
    re.compile(r"(api.?key|secret|password|token).{0,30}[:=]", re.I),
    re.compile(r"(ignore|bypass|override).{0,30}(rule|policy|constraint)", re.I),
]

# Tools that should never be called from untrusted-origin contexts
HIGH_RISK_TOOLS = frozenset({"delete_file", "drop_table", "send_email", "http_post"})

def validate_text_output(text: str) -> OutputValidationResult:
    for pattern in BLOCKED_CONTENT_PATTERNS:
        m = pattern.search(text)
        if m:
            return OutputValidationResult(
                allowed=False,
                reason=f"Policy violation: {m.group(0)!r}",
            )
    return OutputValidationResult(allowed=True, sanitised_text=text)

def validate_tool_call(
    tool_name: str,
    args: dict[str, Any],
    *,
    content_source: ContentSource,
) -> OutputValidationResult:
    if tool_name in HIGH_RISK_TOOLS and content_source in (
        ContentSource.RETRIEVED_DOC,
        ContentSource.TOOL_RESULT,
    ):
        return OutputValidationResult(
            allowed=False,
            reason=f"Tool '{tool_name}' cannot be invoked from untrusted content source",
        )
    # Validate argument types match the tool spec (abbreviated)
    if not isinstance(args, dict):
        return OutputValidationResult(allowed=False, reason="Tool args must be a dict")
    return OutputValidationResult(allowed=True)
